class Solution:
    def beautifulSubstrings(self, s, k):
        n = len(s)
        vowel_set = set('aeiou')
        is_vowel = [1 if c in vowel_set else 0 for c in s]
        prefix_v = [0] * (n + 1)
        for i in range(n):
            prefix_v[i + 1] = prefix_v[i] + is_vowel[i]
        count = 0
        for i in range(n):
            for j in range(i + 1, n + 1):
                length = j - i
                v = prefix_v[j] - prefix_v[i]
                c = length - v
                if v == c and (v * c) % k == 0:
                    count += 1
        return count

