var beautifulSubstrings = function(s, k) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    let x = 1;
    while ((x * x) % k !== 0) x += 1;
    const bucket = new Map();
    const keyOf = (bal, vr) => bal + ':' + vr;
    bucket.set(keyOf(0, 0), 1);
    let balance = 0;
    let vowelCount = 0;
    let ans = 0;
    for (let i = 0; i < s.length; i++) {
        if (vowels.has(s[i])) {
            balance += 1;
            vowelCount += 1;
        } else {
            balance -= 1;
        }
        const key = keyOf(balance, vowelCount % x);
        const cur = bucket.get(key) || 0;
        ans += cur;
        bucket.set(key, cur + 1);
    }
    return ans;
};
